# ── Enums / constants ──────────────────────────────────────────────────────

class Channel:
    CARD      = "CARD"
    ACH       = "ACH"
    WIRE      = "WIRE"
    CRYPTO    = "CRYPTO"


REGULATORY_CAPS: dict[str, Decimal] = {
    Channel.CARD:   Decimal("10_000.00"),
    Channel.ACH:    Decimal("25_000.00"),
    Channel.WIRE:   Decimal("100_000.00"),
    Channel.CRYPTO: Decimal("5_000.00"),
}

COOL_DOWN_HOURS = 2


# ── Custom exceptions ──────────────────────────────────────────────────────

class AppError(Exception):
    pass

class UnauthorisedError(AppError):
    pass

class InsufficientFundsError(AppError):
    pass

class LimitExceededError(AppError):
    pass

class RegulatoryCapExceededError(AppError):
    pass

class CoolDownPeriodError(AppError):
    """Raised when a second limit change is requested before cool-down expires."""
    def __init__(self, eligible_at: datetime):
        self.eligible_at = eligible_at
        super().__init__(f"Cool-down active until {eligible_at}")


# ── Value objects ──────────────────────────────────────────────────────────

from dataclasses import dataclass, field


@dataclass
class LimitConfig:
    channel:    str
    daily_limit: Decimal
    updated_at: datetime
    effective_at: datetime = field(init=False)

    def __post_init__(self):
        self.effective_at = self.updated_at + timedelta(hours=COOL_DOWN_HOURS)

    @property
    def is_effective(self) -> bool:
        return datetime.utcnow() >= self.effective_at


@dataclass
class Customer:
    customer_id: str
    balance: Decimal
    role: str = "customer"   # "customer" | "admin"


@dataclass
class Transaction:
    customer_id: str
    channel: str
    amount: Decimal


# ── Service under test ─────────────────────────────────────────────────────

class LimitRepository:
    """Thin persistence abstraction (will be mocked in tests)."""

    def get_limit(self, customer_id: str, channel: str) -> LimitConfig | None:  # noqa: F821
        raise NotImplementedError

    def save_limit(self, customer_id: str, config: LimitConfig) -> None:
        raise NotImplementedError

    def get_daily_spent(self, customer_id: str, channel: str) -> Decimal:
        raise NotImplementedError


class LimitService:
    """
    Core business logic for per-channel limit management.
    """

    def __init__(self, repo: LimitRepository):
        self._repo = repo

    # ── Configuration ──────────────────────────────────────────────────────

    def configure_limit(
        self,
        requester: Customer,
        target_customer_id: str,
        channel: str,
        new_limit: Decimal,
    ) -> LimitConfig:
        """
        Set a new daily limit for *channel*.  Rules:
        1. Only the account owner or an admin may change limits.
        2. new_limit must be <= regulatory cap for the channel.
        3. If a previous config exists for the same channel, a 2-hour
           cool-down must have elapsed since that change.
        """
        self._assert_authorised(requester, target_customer_id)
        self._assert_within_regulatory_cap(channel, new_limit)
        self._assert_cool_down_elapsed(target_customer_id, channel)

        config = LimitConfig(
            channel=channel,
            daily_limit=new_limit,
            updated_at=datetime.utcnow(),
        )
        self._repo.save_limit(target_customer_id, config)
        return config

    # ── Transaction authorisation ──────────────────────────────────────────

    def authorise_transaction(
        self,
        customer: Customer,
        transaction: Transaction,
    ) -> bool:
        """
        Validate a transaction against:
        - Customer balance
        - Effective daily channel limit
        Returns True if approved; raises on any violation.
        """
        if transaction.amount > customer.balance:
            raise InsufficientFundsError(
                f"Balance {customer.balance} < amount {transaction.amount}"
            )

        config = self._repo.get_limit(customer.customer_id, transaction.channel)
        if config and config.is_effective:
            spent = self._repo.get_daily_spent(customer.customer_id, transaction.channel)
            if spent + transaction.amount > config.daily_limit:
                raise LimitExceededError(
                    f"Daily limit {config.daily_limit} would be exceeded "
                    f"(spent={spent}, txn={transaction.amount})"
                )

        return True

    # ── Private helpers ────────────────────────────────────────────────────

    def _assert_authorised(self, requester: Customer, target_id: str) -> None:
        if requester.role != "admin" and requester.customer_id != target_id:
            raise UnauthorisedError(
                f"Customer {requester.customer_id} may not modify limits for {target_id}"
            )

    def _assert_within_regulatory_cap(self, channel: str, limit: Decimal) -> None:
        cap = REGULATORY_CAPS.get(channel)
        if cap is None:
            raise ValueError(f"Unknown channel: {channel}")
        if limit > cap:
            raise RegulatoryCapExceededError(
                f"Requested limit {limit} exceeds regulatory cap {cap} for {channel}"
            )

    def _assert_cool_down_elapsed(self, customer_id: str, channel: str) -> None:
        existing = self._repo.get_limit(customer_id, channel)
        if existing is None:
            return
        eligible_at = existing.updated_at + timedelta(hours=COOL_DOWN_HOURS)
        if datetime.utcnow() < eligible_at:
            raise CoolDownPeriodError(eligible_at)


