# 1. HAPPY PATH – limit configuration
# ===========================================================================

class TestConfigureLimitHappyPath:

    @freeze_time(BASE_TIME)
    def test_owner_can_set_card_limit_within_cap(self, service, repo, owner):
        """Account owner sets a CARD limit below the regulatory cap."""
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.CARD,
            new_limit=Decimal("500"),
        )

        assert config.channel == Channel.CARD
        assert config.daily_limit == Decimal("500")
        repo.save_limit.assert_called_once_with(owner.customer_id, config)

    @freeze_time(BASE_TIME)
    def test_admin_can_set_limit_for_any_customer(self, service, repo, admin, owner):
        """Admin may change limits for any customer."""
        config = service.configure_limit(
            requester=admin,
            target_customer_id=owner.customer_id,
            channel=Channel.ACH,
            new_limit=Decimal("5_000"),
        )

        assert config.daily_limit == Decimal("5_000")
        repo.save_limit.assert_called_once()

    @freeze_time(BASE_TIME)
    def test_limit_at_exact_regulatory_cap_is_accepted(self, service, repo, owner):
        """A limit equal to the regulatory cap is valid."""
        cap = REGULATORY_CAPS[Channel.WIRE]
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.WIRE,
            new_limit=cap,
        )

        assert config.daily_limit == cap

    @freeze_time(BASE_TIME)
    def test_configure_limit_for_all_supported_channels(self, service, repo, owner):
        """Each channel can be configured independently."""
        for channel, cap in REGULATORY_CAPS.items():
            limit = cap / 2
            config = service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=channel,
                new_limit=limit,
            )
            assert config.channel == channel
            assert config.daily_limit == limit


