class TestCoolDown:

    @freeze_time(BASE_TIME)
    def test_effective_at_is_two_hours_after_update(self, service, repo, owner):
        """LimitConfig.effective_at must equal updated_at + 2 h."""
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.CARD,
            new_limit=Decimal("200"),
        )

        expected_effective = BASE_TIME + timedelta(hours=COOL_DOWN_HOURS)
        assert config.effective_at == expected_effective

    @freeze_time(BASE_TIME)
    def test_limit_not_effective_immediately_after_change(self, service, repo, owner):
        """A freshly saved limit is NOT yet in effect."""
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("200"),
            updated_at=BASE_TIME,
        )
        assert config.is_effective is False

    @freeze_time(BASE_TIME + timedelta(hours=2))
    def test_limit_effective_exactly_at_two_hours(self):
        """LimitConfig is effective exactly at the 2-hour mark."""
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("200"),
            updated_at=BASE_TIME,
        )
        assert config.is_effective is True

    @freeze_time(BASE_TIME + timedelta(hours=2, seconds=1))
    def test_limit_effective_after_two_hours(self):
        """LimitConfig is effective just past the 2-hour mark."""
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("200"),
            updated_at=BASE_TIME,
        )
        assert config.is_effective is True

    @freeze_time(BASE_TIME + timedelta(hours=1, minutes=59))
    def test_second_change_during_cool_down_raises(
        self, service, repo, owner, existing_card_config
    ):
        """A second change before cool-down expires raises CoolDownPeriodError."""
        repo.get_limit.return_value = existing_card_config   # config set at BASE_TIME

        with pytest.raises(CoolDownPeriodError) as exc_info:
            service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=Channel.CARD,
                new_limit=Decimal("300"),
            )

        expected_eligible = BASE_TIME + timedelta(hours=COOL_DOWN_HOURS)
        assert exc_info.value.eligible_at == expected_eligible

    @freeze_time(BASE_TIME + timedelta(hours=2, seconds=1))
    def test_second_change_after_cool_down_succeeds(
        self, service, repo, owner, existing_card_config
    ):
        """A second change is accepted once the cool-down has elapsed."""
        repo.get_limit.return_value = existing_card_config

        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.CARD,
            new_limit=Decimal("800"),
        )

        assert config.daily_limit == Decimal("800")

    @freeze_time(BASE_TIME)
    def test_cool_down_error_contains_eligible_at_timestamp(
        self, service, repo, owner, existing_card_config
    ):
        """CoolDownPeriodError carries the exact moment the customer may retry."""
        repo.get_limit.return_value = existing_card_config

        with pytest.raises(CoolDownPeriodError) as exc_info:
            service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=Channel.CARD,
                new_limit=Decimal("300"),
            )

        assert isinstance(exc_info.value.eligible_at, datetime)

    @freeze_time(BASE_TIME)
    def test_no_cool_down_on_first_ever_configuration(self, service, repo, owner):
        """First-time configuration for a channel has no cool-down requirement."""
        repo.get_limit.return_value = None   # no existing config

        # Should not raise
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.CARD,
            new_limit=Decimal("500"),
        )
        assert config is not None

    @freeze_time(BASE_TIME)
    def test_cool_down_is_per_channel_independent(
        self, service, repo, owner, existing_card_config
    ):
        """Cool-down on CARD channel does not block changes to ACH channel."""
        def get_limit_side_effect(customer_id, channel):
            if channel == Channel.CARD:
                return existing_card_config   # CARD is in cool-down
            return None                       # ACH has no config yet

        repo.get_limit.side_effect = get_limit_side_effect

        # Changing ACH while CARD is cooling should succeed
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.ACH,
            new_limit=Decimal("3_000"),
        )
        assert config.channel == Channel.ACH


