class TestRegulatoryCapExceeded:

    @pytest.mark.parametrize("channel,cap", REGULATORY_CAPS.items())
    @freeze_time(BASE_TIME)
    def test_limit_above_cap_raises_for_all_channels(
        self, service, repo, owner, channel, cap
    ):
        """Every channel rejects a limit above its regulatory cap."""
        with pytest.raises(RegulatoryCapExceededError):
            service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=channel,
                new_limit=cap + Decimal("0.01"),
            )

    @freeze_time(BASE_TIME)
    def test_regulatory_cap_exceeded_does_not_persist(self, service, repo, owner):
        """Repository save must NOT be called when cap is exceeded."""
        with pytest.raises(RegulatoryCapExceededError):
            service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=Channel.CARD,
                new_limit=REGULATORY_CAPS[Channel.CARD] + Decimal("1"),
            )

        repo.save_limit.assert_not_called()

    @freeze_time(BASE_TIME)
    def test_zero_limit_is_accepted(self, service, repo, owner):
        """A limit of zero (freeze channel) is technically within cap."""
        config = service.configure_limit(
            requester=owner,
            target_customer_id=owner.customer_id,
            channel=Channel.CARD,
            new_limit=Decimal("0"),
        )
        assert config.daily_limit == Decimal("0")

    @freeze_time(BASE_TIME)
    def test_negative_limit_raises_value_error(self, service, repo, owner):
        """Negative limits are nonsensical; service must reject them."""
        with pytest.raises((RegulatoryCapExceededError, ValueError)):
            service.configure_limit(
                requester=owner,
                target_customer_id=owner.customer_id,
                channel=Channel.CARD,
                new_limit=Decimal("-1"),
            )

    @freeze_time(BASE_TIME)
    def test_unknown_channel_raises(self, service, repo, owner):
        """Configuring an unrecognised channel raises ValueError."""
        with pytest.raises(ValueError, match="Unknown channel"):
