class TestDailyLimitExceeded:

    @freeze_time(BASE_TIME + timedelta(hours=3))   # cool-down has elapsed
    def test_transaction_exceeding_daily_limit_raises(self, service, repo, owner):
        """Transaction that would breach the daily channel limit is rejected."""
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("1_000"),
            updated_at=BASE_TIME,                # 3 h ago → effective
        )
        repo.get_limit.return_value = config
        repo.get_daily_spent.return_value = Decimal("900")

        txn = Transaction(
            customer_id=owner.customer_id,
            channel=Channel.CARD,
            amount=Decimal("101"),              # 900 + 101 = 1_001 > 1_000
        )

        with pytest.raises(LimitExceededError):
            service.authorise_transaction(owner, txn)

    @freeze_time(BASE_TIME + timedelta(hours=3))
    def test_transaction_exactly_reaching_daily_limit_is_accepted(
        self, service, repo, owner
    ):
        """Transaction that reaches (but does not exceed) the daily limit is ok."""
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("1_000"),
            updated_at=BASE_TIME,
        )
        repo.get_limit.return_value = config
        repo.get_daily_spent.return_value = Decimal("900")

        txn = Transaction(
            customer_id=owner.customer_id,
            channel=Channel.CARD,
            amount=Decimal("100"),               # 900 + 100 == 1_000  ✓
        )

        assert service.authorise_transaction(owner, txn) is True

    @freeze_time(BASE_TIME + timedelta(minutes=30))   # within cool-down window
    def test_new_limit_not_yet_effective_does_not_block_transaction(
        self, service, repo, owner
    ):
        """
        A freshly configured (not-yet-effective) limit must NOT apply.
        The *previous* effective limit (or no limit) should govern the txn.
        """
        # Config set at BASE_TIME is still in cool-down at BASE_TIME + 30 min
        config = LimitConfig(
            channel=Channel.CARD,
            daily_limit=Decimal("50"),          # very low – should not apply yet
            updated_at=BASE_TIME,
        )
        repo.get_limit.return_value = config
        repo.get_daily_spent.return_value = Decimal("0")

        txn = Transaction(
            customer_id=owner.customer_id,
            channel=Channel.CARD,
            amount=Decimal("200"),               # would exceed 50 if limit were active
        )

        # Should NOT raise because limit is not yet effective
        result = service.authorise_transaction(owner, txn)
        assert result is True

    @freeze_time(BASE_TIME + timedelta(hours=3))
    def test_limit_exceeded_error_not_raised_when_no_limit_configured(
        self, service, repo, owner
    ):
        """With no limit configured, high-value transactions are not blocked by limits."""
        repo.get_limit.return_value = None

        txn = Transaction(
            customer_id=owner.customer_id,
            channel=Channel.CARD,
            amount=Decimal("49_999"),            # within balance, no channel limit
        )

        result = service.authorise_transaction(owner, txn)
