        """get_daily_spent must be called with the channel of the transaction."""
        config = LimitConfig(
            channel=Channel.ACH,
            daily_limit=Decimal("5_000"),
            updated_at=BASE_TIME,
        )
        repo.get_limit.return_value = config
        repo.get_daily_spent.return_value = Decimal("0")

        txn = Transaction(
            customer_id=owner.customer_id,
            channel=Channel.ACH,
            amount=Decimal("100"),
        )
        service.authorise_transaction(owner, txn)

        repo.get_daily_spent.assert_called_once_with(owner.customer_id, Channel.ACH)


